#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e5+10;
struct Sort
{
	int pos,val;inline Sort(int x=0,int y=0){pos=x;val=y;}
	inline bool operator<(const Sort &Q)const{return val<Q.val;};
};
struct Pair{int x,y;inline Pair(int xx=0,int yy=0){x=xx;y=yy;}};
set<Sort> S;set<Sort> :: iterator it;
int cmp_Index;inline bool cmp(Sort a,Sort b){if(b<a)swap(a,b);return abs(cmp_Index-a.val)>abs(cmp_Index-b.val);}
int n,a[N],nxt[N][2][20],dis[2][N][2][20];
inline void Init()
{
	rep(1,n+1,i)rep(0,1,j)rep(0,18,k)nxt[i][j][k]=n+1;
	nxt[n-1][1][0]=n;dis[1][n-1][1][0]=abs(a[n]-a[n-1]);	
	S.insert(Sort(n,a[n]));S.insert(Sort(n-1,a[n-1]));
	drep(n-2,1,i)
	{
		Sort s[5];int p=0;
		it=S.lower_bound(Sort(i,a[i]));
		if(it!=S.begin())--it;
		if(it!=S.begin())--it;
		if(it!=S.end())s[p++]=*(it++);
		if(it!=S.end())s[p++]=*(it++);
		if(it!=S.end())s[p++]=*(it++);
		if(it!=S.end())s[p++]=*(it++);
		cmp_Index=a[i];sort(s,s+p,cmp);
		nxt[i][0][0]=s[1].pos;nxt[i][1][0]=s[0].pos;
		dis[0][i][0][0]=abs(s[1].val-a[i]);
		dis[1][i][1][0]=abs(s[0].val-a[i]);
		S.insert(Sort(i,a[i]));
	}
	rep(1,n-1,i)rep(0,1,who)
	{
		nxt[i][who][1]=nxt[nxt[i][who][0]][who^1][0];
		dis[who][i][who][1]=dis[who][i][who][0];
		dis[who^1][i][who][1]=dis[who^1][nxt[i][who][0]][who^1][0];
	}
	rep(2,18,j)rep(0,1,who)rep(1,n-(1<<j)+1,i)
	{
		nxt[i][who][j]=nxt[nxt[i][who][j-1]][who][j-1];
		rep(0,1,qwq)dis[qwq][i][who][j]=dis[qwq][i][who][j-1]+dis[qwq][nxt[i][who][j-1]][who][j-1];
	}
}
inline Pair Cnt(int st,int lm)
{
	Pair res(0,0);int cd=0,cur=st;bool who=0;
	drep(18,1,i)if(cd+dis[0][cur][who][i]+dis[1][cur][who][i]<=lm&&nxt[cur][who][i]<=n)
	{
		int dx=dis[0][cur][who][i],dy=dis[1][cur][who][i];
		res.x+=dx;res.y+=dy;cd+=dx+dy;cur=nxt[cur][who][i];
	}
	if(cd+dis[who][cur][who][0]<=lm&&nxt[cur][who][0]<=n){res.x+=dis[who][cur][who][0];}
	return res;
}
signed main()
{
	n=read();rep(1,n,i)a[i]=read();Init();
//	rep(0,20,i){printf("%lld :: ",i);rep(1,n,j)printf("%lld ",nxt[j][0][i]);puts("");}
//	rep(0,20,i){printf("%lld :: ",i);rep(1,n,j)printf("%lld ",nxt[j][1][i]);puts("");}
//	printf("cao :: %d\n",nxt[9][1][0]);puts("");
	int x0=read(),idx=-1;double mn=4e18;
	rep(1,n,i)
	{
		Pair tmp=Cnt(i,x0);if(!tmp.y)continue;
		1.0*tmp.x/tmp.y+1e-9<mn?mn=1.0*tmp.x/tmp.y,idx=i:0;
	}
	printf("%lld\n",idx);;int Q=read();
	while(Q--)
	{
		int st=read(),lm=read();Pair tmp=Cnt(st,lm);
		printf("%lld %lld\n",tmp.x,tmp.y);
	}
	return 0;
}
